   336→    private func updateSelectedProduct() {
   337→        let productID: String
   338→        switch (selectedTier, selectedPeriod) {
   339→        case (.pro, .monthly): productID = StoreKitProductID.proMonthly
   340→        case (.pro, .annual): productID = StoreKitProductID.proAnnual
   341→        case (.elite, .monthly): productID = StoreKitProductID.eliteMonthly
   342→        case (.elite, .annual): productID = StoreKitProductID.eliteAnnual
   343→        default: productID = StoreKitProductID.proAnnual
   344→        }
   345→        selectedProduct = storeService.product(id: productID)
   346→    }
   347→
   348→    private func productForCard(tier: SubscriptionTier) -> Product? {
   349→        let id = selectedPeriod == .annual
   350→            ? (tier == .pro ? StoreKitProductID.proAnnual : StoreKitProductID.eliteAnnual)
   351→            : (tier == .pro ? StoreKitProductID.proMonthly : StoreKitProductID.eliteMonthly)
   352→        return storeService.product(id: id)
   353→    }
   354→
   355→    private func monthlyEquivalent(for product: Product, tier: SubscriptionTier) -> String {
   356→        // Annual price / 12 months — show as "R$X,XX/mês"
   357→        guard let price = Double(product.price.description) else { return "" }
   358→        let monthly = price / 12.0
   359→        return String(format: "equivale a R$%.2f/mês", monthly).replacingOccurrences(of: ".", with: ",")
   360→    }
