   362→    private var ctaLabel: String {
   363→        guard let product = selectedProduct else {
   364→            return "Assinar \(selectedTier.displayName)"
   365→        }
   366→        return "Assinar \(selectedTier.displayName) — \(product.displayPrice)"
   367→    }
