     6→import Foundation
     7→import StoreKit
     8→
     9→/// Service responsible for StoreKit 2 auto-renewable subscription purchases.
    10→@MainActor
    11→@Observable final class StoreKitService {
    12→    private(set) var products: [Product] = []
    13→    private(set) var purchaseState: PurchaseState = .idle
    14→    private(set) var currentTier: SubscriptionTier = .free
    15→    private(set) var activeProductID: String?
    16→
    17→    // Backwards compat
    18→    var hasProAccess: Bool { currentTier != .free }
    19→
    20→    private nonisolated(unsafe) var transactionListener: Task<Void, Never>?
    21→    private let logger: (String) -> Void
    22→
    23→    enum PurchaseState: Equatable {
    24→        case idle
    25→        case loading
    26→        case purchasing
    27→        case success
    28→        case failed(String)
    29→        case cancelled
    30→    }
    31→
    32→    init(logger: @escaping (String) -> Void = { print("[StoreKit]", $0) }) {
    33→        self.logger = logger
    34→        startTransactionListener()
    35→    }
    36→
    37→    deinit {
    38→        transactionListener?.cancel()
    39→    }
    40→
    41→    // MARK: - Fetch Products
    42→
    43→    func loadProducts() async {
    44→        purchaseState = .loading
    45→        do {
    46→            let storeProducts = try await Product.products(for: StoreKitProductID.allProducts)
    47→            // Sort: Elite Annual, Elite Monthly, Pro Annual, Pro Monthly
    48→            products = storeProducts.sorted { lhs, rhs in
    49→                let lTier = StoreKitProductID.tier(for: lhs.id).level
    50→                let rTier = StoreKitProductID.tier(for: rhs.id).level
    51→                if lTier != rTier { return lTier > rTier }
    52→                return StoreKitProductID.isAnnual(lhs.id) && !StoreKitProductID.isAnnual(rhs.id)
    53→            }
    54→            purchaseState = .idle
    55→            logger("Loaded \(products.count) products")
    56→        } catch {
    57→            logger("Failed to load products: \(error.localizedDescription)")
    58→            purchaseState = .failed("Não foi possível carregar os planos.")
    59→        }
    60→    }
    61→
    62→    // MARK: - Purchase
    63→
    64→    func purchase(_ product: Product) async -> Bool {
    65→        purchaseState = .purchasing
    66→        logger("Initiating purchase for \(product.id)")
    67→
    68→        do {
    69→            let result = try await product.purchase()
    70→
    71→            switch result {
    72→            case .success(let verification):
    73→                let transaction = try checkVerified(verification)
    74→                await transaction.finish()
    75→                await refreshPurchaseStatus()
    76→                purchaseState = .success
    77→                logger("Purchase successful for \(product.id)")
    78→                return true
    79→
    80→            case .userCancelled:
    81→                purchaseState = .cancelled
    82→                logger("User cancelled purchase")
    83→                return false
    84→
    85→            case .pending:
    86→                purchaseState = .idle
    87→                logger("Purchase pending approval")
    88→                return false
    89→
    90→            @unknown default:
    91→                purchaseState = .idle
    92→                return false
    93→            }
    94→        } catch {
    95→            purchaseState = .failed(error.localizedDescription)
    96→            logger("Purchase failed: \(error.localizedDescription)")
    97→            return false
    98→        }
    99→    }
   100→
   101→    // MARK: - Restore Purchases
   102→
   103→    func restorePurchases() async -> Bool {
   104→        purchaseState = .loading
   105→        logger("Restoring purchases...")
   106→
   107→        do {
   108→            try await AppStore.sync()
   109→            await refreshPurchaseStatus()
   110→            purchaseState = currentTier != .free ? .success : .idle
   111→            logger("Restore completed. Tier: \(currentTier.rawValue)")
   112→            return currentTier != .free
   113→        } catch {
   114→            purchaseState = .failed("Não foi possível restaurar compras.")
   115→            logger("Restore failed: \(error.localizedDescription)")
   116→            return false
   117→        }
   118→    }
   119→
   120→    // MARK: - Check Subscription Status
   121→
   122→    func refreshPurchaseStatus() async {
   123→        var highestTier: SubscriptionTier = .free
   124→        var activeID: String?
   125→
   126→        for await verificationResult in Transaction.currentEntitlements {
   127→            guard case .verified(let transaction) = verificationResult else { continue }
   128→            guard StoreKitProductID.allProducts.contains(transaction.productID) else { continue }
   129→            guard transaction.revocationDate == nil else { continue }
   130→
   131→            // For auto-renewable: check expiration
   132→            if let expiry = transaction.expirationDate, expiry < Date() { continue }
   133→
   134→            let tier = StoreKitProductID.tier(for: transaction.productID)
   135→            if tier.level > highestTier.level {
   136→                highestTier = tier
   137→                activeID = transaction.productID
   138→            }
   139→        }
   140→
   141→        currentTier = highestTier
   142→        activeProductID = activeID
   143→        logger("Refreshed status — tier: \(highestTier.rawValue), product: \(activeID ?? "none")")
   144→    }
   145→
   146→    // MARK: - Current Entitlement
   147→
   148→    func getCurrentEntitlement() async -> ProEntitlement {
   149→        await refreshPurchaseStatus()
   150→        guard currentTier != .free else { return .free }
   151→        return ProEntitlement(
   152→            tier: currentTier,
   153→            source: .storeKit,
   154→            expirationDate: await activeSubscriptionExpiry()
   155→        )
   156→    }
   157→
   158→    // MARK: - Product Accessors
   159→
   160→    func products(for tier: SubscriptionTier) -> [Product] {
   161→        products.filter { StoreKitProductID.tier(for: $0.id) == tier }
   162→    }
   163→
   164→    func product(id: String) -> Product? {
   165→        products.first { $0.id == id }
   166→    }
   167→
   168→    // MARK: - Private Helpers
   169→
   170→    private func activeSubscriptionExpiry() async -> Date? {
   171→        guard let activeID = activeProductID else { return nil }
   172→        for await result in Transaction.currentEntitlements {
   173→            if case .verified(let tx) = result, tx.productID == activeID {
   174→                return tx.expirationDate
   175→            }
   176→        }
   177→        return nil
   178→    }
   179→
   180→    private func startTransactionListener() {
   181→        transactionListener = Task.detached { [weak self] in
   182→            for await result in Transaction.updates {
   183→                await self?.handleTransactionUpdate(result)
   184→            }
   185→        }
   186→    }
   187→
   188→    private func handleTransactionUpdate(_ result: VerificationResult<Transaction>) async {
   189→        switch result {
   190→        case .verified(let transaction):
   191→            logger("Transaction update: \(transaction.productID)")
   192→            await transaction.finish()
   193→            await refreshPurchaseStatus()
   194→        case .unverified(_, let error):
   195→            logger("Unverified transaction: \(error.localizedDescription)")
   196→        }
   197→    }
   198→
   199→    private func checkVerified<T>(_ result: VerificationResult<T>) throws -> T {
   200→        switch result {
   201→        case .unverified(_, let error): throw error
   202→        case .verified(let safe): return safe
   203→        }
   204→    }
   205→}
