 12→/// Segments available in the Activity tab.
 13→enum ActivitySegment: String, CaseIterable {
 14→    case history = "Histórico"
 15→    case challenges = "Desafios"
 16→    case stats = "Stats"
 17→}
 18→
 19→/// Main view for the Activity tab.
 20→struct ActivityTabView: View {
 21→    let resolver: Resolver
 22→
 23→    @State private var selectedSegment: ActivitySegment = .history
 24→
 25→    var body: some View {
 26→        VStack(spacing: 0) {
 27→            // Segmented Control
 28→            segmentedControl
 29→                .padding(.horizontal, FitTodaySpacing.md)
 30→                .padding(.vertical, FitTodaySpacing.sm)
 31→
 32→            // Content
 33→            TabView(selection: $selectedSegment) {
 34→                WorkoutHistoryView(resolver: resolver)
 35→                    .tag(ActivitySegment.history)
 36→
 37→                ChallengesFullListView(resolver: resolver)
 38→                    .tag(ActivitySegment.challenges)
 39→
 40→                ActivityStatsView(resolver: resolver)
 41→                    .tag(ActivitySegment.stats)
 42→            }
 43→            .tabViewStyle(.page(indexDisplayMode: .never))
