 59→                } label: {
 60→                    Text(segment.rawValue)
 61→                        .font(FitTodayFont.ui(size: 14, weight: selectedSegment == segment ? .bold : .medium))
 62→                        .foregroundStyle(selectedSegment == segment ? FitTodayColor.textPrimary : FitTodayColor.textSecondary)
 63→                        .frame(maxWidth: .infinity)
