 81→// MARK: - Workout History View
 82→
 83→struct WorkoutHistoryView: View {
 84→    let resolver: Resolver
 85→
 86→    @State private var selectedDate = Date()
 87→    @State private var workouts: [WorkoutHistoryEntry] = []
 88→    @State private var isLoading = true
 89→    @State private var listAppeared = false
 90→
 91→    private var repository: WorkoutHistoryRepository? {
 92→        resolver.resolve(WorkoutHistoryRepository.self)
 93→    }
 94→
 95→    private var workoutDays: Set<DateComponents> {
 96→        let calendar = Calendar.current
