101→
102→    var body: some View {
103→        ScrollView {
104→            VStack(spacing: FitTodaySpacing.lg) {
105→                // Calendar
106→                calendarSection
107→
108→                // Workout List
109→                workoutListSection
110→            }
111→            .padding(FitTodaySpacing.md)
112→        }
113→        .scrollIndicators(.hidden)
114→        .task {
115→            await loadWorkouts()
116→        }
117→    }
118→
119→    // MARK: - Calendar Section
120→
121→    private var calendarSection: some View {
122→        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
123→            Text("Calendário")
124→                .font(FitTodayFont.ui(size: 17, weight: .bold))
125→                .foregroundStyle(FitTodayColor.textPrimary)
126→
127→            // Simple month calendar
128→            MonthCalendarView(
129→                selectedDate: $selectedDate,
130→                highlightedDays: workoutDays
131→            )
132→        }
133→    }
134→
135→    // MARK: - Workout List Section
136→
137→    private var workoutListSection: some View {
138→        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
139→            Text("Treinos Recentes")
140→                .font(FitTodayFont.ui(size: 17, weight: .bold))
141→                .foregroundStyle(FitTodayColor.textPrimary)
142→
143→            if isLoading {
144→                loadingView
145→            } else if workouts.isEmpty {
146→                emptyStateView
147→            } else {
148→                LazyVStack(spacing: FitTodaySpacing.sm) {
149→                    ForEach(Array(workouts.enumerated()), id: \.element.id) { index, entry in
150→                        WorkoutEntryCard(entry: entry)
151→                            .opacity(listAppeared ? 1 : 0)
152→                            .offset(y: listAppeared ? 0 : 16)
153→                            .animation(
154→                                .easeOut(duration: 0.3).delay(Double(index) * 0.05),
155→                                value: listAppeared
156→                            )
157→                    }
158→                }
159→                .onAppear {
160→                    listAppeared = false
161→                    withAnimation { listAppeared = true }
162→                }
163→            }
164→        }
165→    }
166→
167→    private var loadingView: some View {
168→        VStack(spacing: FitTodaySpacing.sm) {
169→            ForEach(0..<4, id: \.self) { _ in
170→                RoundedRectangle(cornerRadius: FitTodayRadius.md)
171→                    .fill(FitTodayColor.surface)
172→                    .frame(height: 80)
173→                    .shimmer()
174→            }
175→        }
176→    }
177→
178→    private var emptyStateView: some View {
179→        VStack(spacing: FitTodaySpacing.md) {
180→            Image(systemName: "figure.run.circle")
181→                .font(.system(size: 48))
182→                .foregroundStyle(FitTodayColor.textTertiary)
183→
184→            Text("Nenhum treino ainda")
185→                .font(FitTodayFont.ui(size: 17, weight: .semiBold))
186→                .foregroundStyle(FitTodayColor.textPrimary)
187→
188→            Text("Complete seu primeiro treino para ver seu histórico")
189→                .font(FitTodayFont.ui(size: 14, weight: .medium))
190→                .foregroundStyle(FitTodayColor.textSecondary)
191→                .multilineTextAlignment(.center)
192→        }
193→        .frame(maxWidth: .infinity)
194→        .padding(FitTodaySpacing.xl)
195→    }
196→
197→    // MARK: - Data Loading
198→
199→    private func loadWorkouts() async {
200→        guard let repository else {
201→            isLoading = false
202→            return
203→        }
204→
205→        do {
206→            let entries = try await repository.listEntries(limit: 20, offset: 0)
207→            workouts = entries
208→        } catch {
209→            workouts = []
210→        }
211→        isLoading = false
212→    }
213→}
