215→// MARK: - Month Calendar View
216→
217→struct MonthCalendarView: View {
218→    @Binding var selectedDate: Date
219→    let highlightedDays: Set<DateComponents>
220→
221→    // BUG 7 FIX: use Monday-first week to match startOfWeek used by weekly stats.
222→    private let calendar: Calendar = {
223→        var cal = Calendar.current
224→        cal.firstWeekday = 2 // Monday = 2
225→        return cal
226→    }()
227→    // Mon, Tue, Wed, Thu, Fri, Sat, Sun
228→    private let daysOfWeek = ["S", "T", "Q", "Q", "S", "S", "D"]
229→
230→    private var monthDays: [Date?] {
231→        let interval = calendar.dateInterval(of: .month, for: selectedDate)!
232→        let firstDay = interval.start
233→        // weekday in Calendar.current is 1=Sun … 7=Sat.
234→        // Convert to Monday-first column index: Mon=0 … Sun=6.
235→        let firstWeekday = Calendar.current.component(.weekday, from: firstDay)
236→        let mondayFirstOffset = (firstWeekday - 2 + 7) % 7
237→        let daysInMonth = calendar.range(of: .day, in: .month, for: selectedDate)!.count
238→
239→        var days: [Date?] = Array(repeating: nil, count: mondayFirstOffset)
240→
241→        for day in 1...daysInMonth {
242→            if let date = calendar.date(byAdding: .day, value: day - 1, to: firstDay) {
243→                days.append(date)
244→            }
245→        }
246→
247→        // Pad to complete last week
248→        while days.count % 7 != 0 {
249→            days.append(nil)
250→        }
251→
252→        return days
253→    }
254→
255→    var body: some View {
256→        VStack(spacing: FitTodaySpacing.sm) {
257→            // Month navigation
258→            HStack {
259→                Button {
260→                    withAnimation {
261→                        selectedDate = calendar.date(byAdding: .month, value: -1, to: selectedDate)!
262→                    }
263→                } label: {
264→                    Image(systemName: "chevron.left")
265→                        .foregroundStyle(FitTodayColor.textSecondary)
266→                }
267→
268→                Spacer()
269→
270→                Text(selectedDate, format: .dateTime.month(.wide).year())
271→                    .font(FitTodayFont.ui(size: 16, weight: .semiBold))
272→                    .foregroundStyle(FitTodayColor.textPrimary)
273→
274→                Spacer()
275→
276→                Button {
277→                    withAnimation {
278→                        selectedDate = calendar.date(byAdding: .month, value: 1, to: selectedDate)!
279→                    }
280→                } label: {
281→                    Image(systemName: "chevron.right")
282→                        .foregroundStyle(FitTodayColor.textSecondary)
283→                }
284→            }
285→            .padding(.horizontal, FitTodaySpacing.sm)
286→
287→            // Days of week header
288→            HStack(spacing: 0) {
289→                ForEach(daysOfWeek, id: \.self) { day in
290→                    Text(day)
291→                        .font(FitTodayFont.ui(size: 12, weight: .medium))
292→                        .foregroundStyle(FitTodayColor.textTertiary)
293→                        .frame(maxWidth: .infinity)
294→                }
295→            }
296→
297→            // Calendar grid
298→            LazyVGrid(columns: Array(repeating: GridItem(.flexible()), count: 7), spacing: FitTodaySpacing.xs) {
299→                ForEach(Array(monthDays.enumerated()), id: \.offset) { _, date in
300→                    if let date {
301→                        DayCell(
302→                            date: date,
303→                            isHighlighted: isHighlighted(date),
304→                            isSelected: calendar.isDate(date, inSameDayAs: selectedDate),
305→                            isToday: calendar.isDateInToday(date)
306→                        ) {
307→                            selectedDate = date
308→                        }
309→                    } else {
310→                        Color.clear
311→                            .frame(width: 36, height: 36)
312→                    }
313→                }
314→            }
315→        }
316→        .padding(FitTodaySpacing.md)
317→        .background(
318→            RoundedRectangle(cornerRadius: FitTodayRadius.md)
319→                .fill(FitTodayColor.surface)
320→        )
321→    }
322→
323→    private func isHighlighted(_ date: Date) -> Bool {
324→        let components = calendar.dateComponents([.year, .month, .day], from: date)
325→        return highlightedDays.contains(components)
326→    }
327→}
